INSERT INTO AUTH_LOGIN_TOKEN (
    token_id, token_hash, subject_type, parent_id, expires_at
) VALUES (
    seq_auth_login_token.NEXTVAL, #{tokenHash}, 'parent', #{parentId}, #{expiresAt}
)

INSERT INTO AUTH_LOGIN_TOKEN (
    token_id, token_hash, subject_type, child_id, expires_at
) VALUES (
    seq_auth_login_token.NEXTVAL, #{tokenHash}, 'child', #{childId}, #{expiresAt}
)
